import modal

app = modal.App("class-inference-warm")

image = modal.Image.debian_slim().pip_install("numpy")


@app.cls(image=image, min_containers=1)
class TextClassifier:
    @modal.enter()
    def setup(self):
        self.model = {"name": "naive-keyword-classifier", "version": "1.0"}
        self.call_count = 0

    @modal.method()
    def classify(self, text: str) -> dict:
        self.call_count += 1

        positive_words = {"good", "great", "excellent", "happy", "love", "wonderful", "fantastic", "amazing", "best"}
        negative_words = {"bad", "terrible", "awful", "hate", "horrible", "worst", "disgusting", "dreadful", "poor"}

        words = set(text.lower().split())
        pos_hits = len(words & positive_words)
        neg_hits = len(words & negative_words)

        if pos_hits > neg_hits:
            label = "positive"
            confidence = round(0.5 + 0.1 * pos_hits, 2)
        elif neg_hits > pos_hits:
            label = "negative"
            confidence = round(0.5 + 0.1 * neg_hits, 2)
        else:
            label = "neutral"
            confidence = 0.5

        confidence = min(confidence, 1.0)

        return {
            "label": label,
            "confidence": confidence,
            "call_count": self.call_count,
        }

    @modal.method()
    def get_stats(self) -> dict:
        return {
            "model_info": self.model,
            "total_calls": self.call_count,
        }


@app.local_entrypoint()
def main():
    classifier = TextClassifier()

    results = [
        classifier.classify.remote("This is a great and wonderful experience"),
        classifier.classify.remote("This is a terrible and awful situation"),
        classifier.classify.remote("The weather is okay today"),
    ]

    stats = classifier.get_stats.remote()

    output_dict = modal.Dict.from_name("class-inference-output", create_if_missing=True)
    output_dict["stats"] = stats
    output_dict["classifications"] = 3

    print("Classification results:")
    for i, result in enumerate(results, 1):
        print(f"  [{i}] {result}")

    print(f"\nStats: {stats}")
    print("\nResults stored in Modal Dict 'class-inference-output'.")
